import{_ as r,o,c as a,a3 as e}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"37. Penalty Payments","description":"","frontmatter":{"title":"37. Penalty Payments","eba":"Doctors in Training 2022-2026","topics":["hours","overtime","shift-work"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/37-penalty-payments.md","filePath":"ebas/doctors-in-training/hours-of-work/37-penalty-payments.md"}'),n={name:"ebas/doctors-in-training/hours-of-work/37-penalty-payments.md"};function s(i,t,p,h,d,f){return o(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_37-penalty-payments" tabindex="-1">37. Penalty Payments <a class="header-anchor" href="#_37-penalty-payments" aria-label="Permalink to &quot;37. Penalty Payments&quot;">​</a></h1><p><strong>37.1</strong> The provisions of this clause 37 are to be read in conjunction with subclauses 42.7(d) and 42.7(e) (Rate of Pay).</p><p><strong>37.2</strong> Saturday and Sunday Work</p><p><strong>(a)</strong> Any ordinary hours performed between midnight Friday and midnight Sunday must be paid at 150% of the Doctor’s ordinary hourly rate of pay.</p><p><strong>(b)</strong> For hours worked between midnight Friday and midnight Sunday that are in excess of ordinary hours pursuant to subclause 33.1, overtime rates pursuant to subclause</p><p><strong>36.2</strong> must be paid.</p><p><strong>37.3</strong> Shift Penalty</p><p><strong>(a)</strong> An additional 2.5% of the ordinary weekly rate of pay for the 1st year of experience rate applicable to the Doctor’s classification must be paid for each shift worked for a rostered shift finishing after 6 p.m.</p><p><strong>(b)</strong> From 1 March 2023 onwards, where a Doctor works a rostered shift on a Friday that finishes after 6:00pm, the Doctor will be paid a pro-rata allowance proportionate to rostered hours that fall prior to 6:00pm against the full shift length.</p><p>Example:</p><p>A Doctor is rostered for an eight (8) hour shift from 2:00pm to 10:00pm on a Friday.</p><p>The Doctor will receive 50% of the Shift Penalty Payment as four hours of the eight hour shift fall prior to 6:00pm.</p><p>In addition, the Doctor will receive Friday Night Evening Shift Penalty of 25% for hours worked from 6:00pm until 10:00pm.</p><p><strong>37.4</strong> Friday Evening Shifts (from 1 March 2023 onwards)</p><p><strong>(a)</strong> From 1 March 2023 onwards, hours worked on Friday between 6:00pm and midnight will attract a penalty payment of 25% of the Doctor’s ordinary base hourly rate of pay for each hour worked within that period.</p><p><strong>37.5</strong> Night Duty Allowance</p><p><strong>(a)</strong> An additional 25% of the Doctor’s ordinary base hourly rate of pay must be paid for:</p><p><strong>(i)</strong> each hour worked during a rostered shift finishing the day after work began; or</p><p><strong>(ii)</strong> each hour worked during a rostered shift beginning after midnight and before 6.30 a.m.</p><p>Plain language terms: penalty rates, shift penalty.</p>',20)])])}const g=r(n,[["render",s]]);export{y as __pageData,g as default};
